#Requires -Modules Pester
# TDD test suite for SemanticVersionBumper.ps1
# Red/Green cycle: tests written first, then implementation added to make them pass.

BeforeAll {
    $scriptPath = Join-Path $PSScriptRoot "SemanticVersionBumper.ps1"
    . $scriptPath
}

Describe "Get-BumpType" {
    # RED: these fail until Get-BumpType is implemented

    It "returns major for feat! (exclamation breaking change)" {
        $commits = @("feat!: redesign public API")
        Get-BumpType -Commits $commits | Should -Be "major"
    }

    It "returns major for fix! (exclamation breaking change)" {
        $commits = @("fix!: remove deprecated parameter")
        Get-BumpType -Commits $commits | Should -Be "major"
    }

    It "returns major for BREAKING CHANGE in commit body" {
        $commits = @("feat: new thing`n`nBREAKING CHANGE: removes old API")
        Get-BumpType -Commits $commits | Should -Be "major"
    }

    It "returns major even when feat also present" {
        $commits = @("feat: add feature", "feat!: break everything")
        Get-BumpType -Commits $commits | Should -Be "major"
    }

    It "returns minor for feat: commits" {
        $commits = @("feat: add OAuth2 login", "fix: typo in readme")
        Get-BumpType -Commits $commits | Should -Be "minor"
    }

    It "returns minor for feat with scope" {
        $commits = @("feat(auth): add JWT support")
        Get-BumpType -Commits $commits | Should -Be "minor"
    }

    It "returns patch for fix: commits only" {
        $commits = @("fix: correct null pointer", "fix: handle empty response")
        Get-BumpType -Commits $commits | Should -Be "patch"
    }

    It "returns patch for fix with scope" {
        $commits = @("fix(api): handle timeout correctly")
        Get-BumpType -Commits $commits | Should -Be "patch"
    }

    It "returns none for chore/docs/style commits" {
        $commits = @("chore: update deps", "docs: improve readme", "style: reformat")
        Get-BumpType -Commits $commits | Should -Be "none"
    }

    It "returns none for empty commit list" {
        Get-BumpType -Commits @() | Should -Be "none"
    }

    It "minor wins over patch when both present" {
        $commits = @("fix: bugfix", "feat: new feature")
        Get-BumpType -Commits $commits | Should -Be "minor"
    }

    It "major wins over minor when both present" {
        $commits = @("feat: new feature", "feat!: breaking redesign")
        Get-BumpType -Commits $commits | Should -Be "major"
    }
}

Describe "Get-NewVersion" {
    # RED: these fail until Get-NewVersion is implemented

    It "bumps major: 1.0.0 -> 2.0.0" {
        Get-NewVersion -CurrentVersion "1.0.0" -BumpType "major" | Should -Be "2.0.0"
    }

    It "bumps major: 2.5.3 -> 3.0.0" {
        Get-NewVersion -CurrentVersion "2.5.3" -BumpType "major" | Should -Be "3.0.0"
    }

    It "bumps minor: 1.0.0 -> 1.1.0" {
        Get-NewVersion -CurrentVersion "1.0.0" -BumpType "minor" | Should -Be "1.1.0"
    }

    It "bumps minor: 2.5.3 -> 2.6.0" {
        Get-NewVersion -CurrentVersion "2.5.3" -BumpType "minor" | Should -Be "2.6.0"
    }

    It "bumps patch: 1.0.0 -> 1.0.1" {
        Get-NewVersion -CurrentVersion "1.0.0" -BumpType "patch" | Should -Be "1.0.1"
    }

    It "bumps patch: 2.5.3 -> 2.5.4" {
        Get-NewVersion -CurrentVersion "2.5.3" -BumpType "patch" | Should -Be "2.5.4"
    }

    It "no bump: 1.2.3 stays at 1.2.3" {
        Get-NewVersion -CurrentVersion "1.2.3" -BumpType "none" | Should -Be "1.2.3"
    }

    It "major bump resets minor and patch to zero" {
        Get-NewVersion -CurrentVersion "3.7.12" -BumpType "major" | Should -Be "4.0.0"
    }

    It "minor bump resets patch to zero" {
        Get-NewVersion -CurrentVersion "3.7.12" -BumpType "minor" | Should -Be "3.8.0"
    }

    It "throws for invalid version string" {
        { Get-NewVersion -CurrentVersion "not-a-version" -BumpType "patch" } | Should -Throw
    }
}

Describe "Get-ChangelogEntry" {
    # RED: these fail until Get-ChangelogEntry is implemented

    It "includes version header" {
        $result = Get-ChangelogEntry -NewVersion "1.0.1" -Commits @("fix: a bug") -Date ([DateTime]"2026-01-15")
        $result | Should -Match "\[1\.0\.1\]"
    }

    It "includes date in header" {
        $result = Get-ChangelogEntry -NewVersion "1.0.1" -Commits @("fix: a bug") -Date ([DateTime]"2026-01-15")
        $result | Should -Match "2026-01-15"
    }

    It "lists fix commits under Bug Fixes section" {
        $result = Get-ChangelogEntry -NewVersion "1.0.1" -Commits @("fix: correct null pointer") -Date ([DateTime]"2026-01-15")
        $result | Should -Match "Bug Fixes"
        $result | Should -Match "fix: correct null pointer"
    }

    It "lists feat commits under Features section" {
        $result = Get-ChangelogEntry -NewVersion "1.1.0" -Commits @("feat: add OAuth2") -Date ([DateTime]"2026-01-15")
        $result | Should -Match "Features"
        $result | Should -Match "feat: add OAuth2"
    }

    It "lists breaking changes under Breaking Changes section" {
        $result = Get-ChangelogEntry -NewVersion "2.0.0" -Commits @("feat!: redesign API") -Date ([DateTime]"2026-01-15")
        $result | Should -Match "Breaking Changes"
        $result | Should -Match "feat!: redesign API"
    }

    It "does not include empty sections" {
        $result = Get-ChangelogEntry -NewVersion "1.0.1" -Commits @("fix: a bug") -Date ([DateTime]"2026-01-15")
        $result | Should -Not -Match "Features"
        $result | Should -Not -Match "Breaking Changes"
    }
}

Describe "Invoke-SemanticVersionBump (integration)" {
    # RED: full script integration tests

    BeforeEach {
        $tmpDir = Join-Path ([System.IO.Path]::GetTempPath()) ([System.Guid]::NewGuid().ToString())
        New-Item -ItemType Directory -Path $tmpDir | Out-Null
    }

    AfterEach {
        if (Test-Path $tmpDir) { Remove-Item -Recurse -Force $tmpDir }
    }

    It "reads version.json and outputs new version" {
        $versionFile = Join-Path $tmpDir "version.json"
        $commitsFile = Join-Path $tmpDir "commits.txt"
        '{"version":"1.0.0"}' | Set-Content $versionFile
        "fix: a bug" | Set-Content $commitsFile

        $output = & $scriptPath -VersionFile $versionFile -CommitsFile $commitsFile
        $output | Should -Match "NEW_VERSION=1\.0\.1"
    }

    It "reads package.json version field" {
        $versionFile = Join-Path $tmpDir "package.json"
        $commitsFile = Join-Path $tmpDir "commits.txt"
        '{"name":"my-app","version":"2.3.0","description":"test"}' | Set-Content $versionFile
        "feat: add feature" | Set-Content $commitsFile

        $output = & $scriptPath -VersionFile $versionFile -CommitsFile $commitsFile
        $output | Should -Match "NEW_VERSION=2\.4\.0"
    }

    It "updates version file with new version" {
        $versionFile = Join-Path $tmpDir "version.json"
        $commitsFile = Join-Path $tmpDir "commits.txt"
        '{"version":"1.0.0"}' | Set-Content $versionFile
        "feat!: breaking change" | Set-Content $commitsFile

        & $scriptPath -VersionFile $versionFile -CommitsFile $commitsFile | Out-Null
        $updated = Get-Content $versionFile | ConvertFrom-Json
        $updated.version | Should -Be "2.0.0"
    }

    It "does not update version file when -DryRun" {
        $versionFile = Join-Path $tmpDir "version.json"
        $commitsFile = Join-Path $tmpDir "commits.txt"
        '{"version":"1.0.0"}' | Set-Content $versionFile
        "feat: new thing" | Set-Content $commitsFile

        & $scriptPath -VersionFile $versionFile -CommitsFile $commitsFile -DryRun | Out-Null
        $unchanged = Get-Content $versionFile | ConvertFrom-Json
        $unchanged.version | Should -Be "1.0.0"
    }

    It "writes changelog entry to CHANGELOG.md" {
        $versionFile = Join-Path $tmpDir "version.json"
        $commitsFile = Join-Path $tmpDir "commits.txt"
        $changelogFile = Join-Path $tmpDir "CHANGELOG.md"
        '{"version":"1.0.0"}' | Set-Content $versionFile
        "fix: resolve memory leak" | Set-Content $commitsFile

        & $scriptPath -VersionFile $versionFile -CommitsFile $commitsFile -ChangelogFile $changelogFile | Out-Null
        $changelog = Get-Content $changelogFile -Raw
        $changelog | Should -Match "\[1\.0\.1\]"
        $changelog | Should -Match "fix: resolve memory leak"
    }

    It "prepends to existing CHANGELOG.md" {
        $versionFile = Join-Path $tmpDir "version.json"
        $commitsFile = Join-Path $tmpDir "commits.txt"
        $changelogFile = Join-Path $tmpDir "CHANGELOG.md"
        '{"version":"1.0.0"}' | Set-Content $versionFile
        "fix: bug" | Set-Content $commitsFile
        "# Changelog`n`n## [0.9.0] - 2025-01-01`n`n- old entry" | Set-Content $changelogFile

        & $scriptPath -VersionFile $versionFile -CommitsFile $commitsFile -ChangelogFile $changelogFile | Out-Null
        $changelog = Get-Content $changelogFile -Raw
        $changelog | Should -Match "\[1\.0\.1\]"
        $changelog | Should -Match "\[0\.9\.0\]"
    }

    It "exits with error for missing version file" {
        $commitsFile = Join-Path $tmpDir "commits.txt"
        "fix: bug" | Set-Content $commitsFile

        { & $scriptPath -VersionFile "$tmpDir/nonexistent.json" -CommitsFile $commitsFile } | Should -Throw
    }

    It "outputs current version unchanged when no relevant commits" {
        $versionFile = Join-Path $tmpDir "version.json"
        $commitsFile = Join-Path $tmpDir "commits.txt"
        '{"version":"1.2.3"}' | Set-Content $versionFile
        "chore: update deps`ndocs: fix typo" | Set-Content $commitsFile

        $output = & $scriptPath -VersionFile $versionFile -CommitsFile $commitsFile
        $output | Should -Match "NEW_VERSION=1\.2\.3"
    }
}

Describe "Workflow Structure" {
    # RED: workflow file doesn't exist yet

    BeforeAll {
        $workflowPath = Join-Path $PSScriptRoot ".github/workflows/semantic-version-bumper.yml"
        $workflowContent = Get-Content $workflowPath -Raw -ErrorAction SilentlyContinue
        $workflow = $null
        if ($workflowContent) {
            # Parse YAML by looking for keys (simple PowerShell YAML-like parse)
            $workflow = $workflowContent
        }
    }

    It "workflow file exists" {
        $workflowPath = Join-Path $PSScriptRoot ".github/workflows/semantic-version-bumper.yml"
        Test-Path $workflowPath | Should -Be $true
    }

    It "workflow has push trigger" {
        $workflow | Should -Match "push:"
    }

    It "workflow has workflow_dispatch trigger" {
        $workflow | Should -Match "workflow_dispatch"
    }

    It "workflow references SemanticVersionBumper.ps1" {
        $workflow | Should -Match "SemanticVersionBumper\.ps1"
    }

    It "workflow uses shell: pwsh" {
        $workflow | Should -Match "shell:\s*pwsh"
    }

    It "workflow uses actions/checkout@v4" {
        $workflow | Should -Match "actions/checkout@v4"
    }

    It "script file exists at referenced path" {
        $scriptPath = Join-Path $PSScriptRoot "SemanticVersionBumper.ps1"
        Test-Path $scriptPath | Should -Be $true
    }

    It "actionlint passes on workflow file" {
        $workflowPath = Join-Path $PSScriptRoot ".github/workflows/semantic-version-bumper.yml"
        $result = & actionlint $workflowPath 2>&1
        $LASTEXITCODE | Should -Be 0
    }
}

Describe "Act Integration Tests" {
    # These tests run the full workflow via act for each test case.
    # They write all output to act-result.txt.

    BeforeAll {
        $script:actResultFile = Join-Path $PSScriptRoot "act-result.txt"
        # Start fresh
        if (Test-Path $script:actResultFile) { Remove-Item $script:actResultFile }
        Set-Content $script:actResultFile "# Act Integration Test Results`n"

        $script:workspaceRoot = $PSScriptRoot
        $script:scriptSrc = Join-Path $PSScriptRoot "SemanticVersionBumper.ps1"
        $script:workflowSrc = Join-Path $PSScriptRoot ".github/workflows/semantic-version-bumper.yml"
        $script:actrcSrc = Join-Path $PSScriptRoot ".actrc"
    }

    # Helper: set up a temp git repo with the given version and commits, run act push --rm,
    # capture all output and append to act-result.txt. Returns output as string array.
    function Invoke-ActTestCase {
        param(
            [string]$TestName,
            [string]$VersionJson,
            [string]$CommitsTxt
        )

        $tmpDir = Join-Path ([System.IO.Path]::GetTempPath()) ([System.Guid]::NewGuid().ToString())
        New-Item -ItemType Directory -Path $tmpDir | Out-Null
        New-Item -ItemType Directory -Path "$tmpDir/.github/workflows" -Force | Out-Null

        # Copy script and workflow into the temp repo
        Copy-Item $script:scriptSrc "$tmpDir/SemanticVersionBumper.ps1"
        Copy-Item $script:workflowSrc "$tmpDir/.github/workflows/semantic-version-bumper.yml"

        # Copy .actrc so act uses the correct container image
        if (Test-Path $script:actrcSrc) {
            Copy-Item $script:actrcSrc "$tmpDir/.actrc"
        }

        # Write test-case-specific files
        $VersionJson | Set-Content "$tmpDir/version.json" -Encoding UTF8
        $CommitsTxt  | Set-Content "$tmpDir/commits.txt"  -Encoding UTF8

        # Initialise git repo
        Push-Location $tmpDir
        & git init --quiet
        & git config user.email "test@example.com"
        & git config user.name "Test Runner"
        & git add -A
        & git commit -m "test: $TestName" --quiet

        # Run act
        $actOutput = & act push --rm 2>&1
        $actExit = $LASTEXITCODE
        Pop-Location

        # Cleanup
        Remove-Item -Recurse -Force $tmpDir -ErrorAction SilentlyContinue

        # Append to act-result.txt
        $delimiter = "=" * 60
        Add-Content $script:actResultFile "`n$delimiter"
        Add-Content $script:actResultFile "TEST CASE: $TestName"
        Add-Content $script:actResultFile "EXIT CODE: $actExit"
        Add-Content $script:actResultFile $delimiter
        $actOutput | ForEach-Object { Add-Content $script:actResultFile $_ }
        Add-Content $script:actResultFile "$delimiter`n"

        return @{
            Output   = $actOutput
            ExitCode = $actExit
        }
    }

    It "act-result.txt is written after all cases run" {
        # This test runs last conceptually; we just verify the file path is set
        $script:actResultFile | Should -Not -BeNullOrEmpty
    }

    It "patch bump: fix commits on 1.0.0 produce NEW_VERSION=1.0.1" {
        $commits = Get-Content (Join-Path $PSScriptRoot "fixtures/patch-commits.txt") -Raw
        $result = Invoke-ActTestCase -TestName "patch-bump" `
            -VersionJson '{"version":"1.0.0"}' `
            -CommitsTxt $commits

        $result.ExitCode | Should -Be 0
        $result.Output -join "`n" | Should -Match "NEW_VERSION=1\.0\.1"
        $result.Output -join "`n" | Should -Match "Job succeeded"
    }

    It "minor bump: feat commits on 1.0.0 produce NEW_VERSION=1.1.0" {
        $commits = Get-Content (Join-Path $PSScriptRoot "fixtures/minor-commits.txt") -Raw
        $result = Invoke-ActTestCase -TestName "minor-bump" `
            -VersionJson '{"version":"1.0.0"}' `
            -CommitsTxt $commits

        $result.ExitCode | Should -Be 0
        $result.Output -join "`n" | Should -Match "NEW_VERSION=1\.1\.0"
        $result.Output -join "`n" | Should -Match "Job succeeded"
    }

    It "major bump: breaking commits on 1.0.0 produce NEW_VERSION=2.0.0" {
        $commits = Get-Content (Join-Path $PSScriptRoot "fixtures/major-commits.txt") -Raw
        $result = Invoke-ActTestCase -TestName "major-bump" `
            -VersionJson '{"version":"1.0.0"}' `
            -CommitsTxt $commits

        $result.ExitCode | Should -Be 0
        $result.Output -join "`n" | Should -Match "NEW_VERSION=2\.0\.0"
        $result.Output -join "`n" | Should -Match "Job succeeded"
    }

    It "no bump: noop commits on 2.5.3 produce NEW_VERSION=2.5.3" {
        $commits = Get-Content (Join-Path $PSScriptRoot "fixtures/noop-commits.txt") -Raw
        $result = Invoke-ActTestCase -TestName "noop-bump" `
            -VersionJson '{"version":"2.5.3"}' `
            -CommitsTxt $commits

        $result.ExitCode | Should -Be 0
        $result.Output -join "`n" | Should -Match "NEW_VERSION=2\.5\.3"
        $result.Output -join "`n" | Should -Match "Job succeeded"
    }

    It "act-result.txt file exists after act tests" {
        Test-Path $script:actResultFile | Should -Be $true
    }
}

