        Get-BumpType -Commits $commits | Should -Be "major"
    }

    It "returns major for fix! (exclamation breaking change)" {
        $commits = @("fix!: remove deprecated parameter")
        Get-BumpType -Commits $commits | Should -Be "major"
    }

    It "returns major for BREAKING CHANGE in commit body" {
        $commits = @("feat: new thing`n`nBREAKING CHANGE: removes old API")
        Get-BumpType -Commits $commits | Should -Be "major"
    }

    It "returns major even when feat also present" {
        $commits = @("feat: add feature", "feat!: break everything")
        Get-BumpType -Commits $commits | Should -Be "major"
    }

    It "returns minor for feat: commits" {
        $commits = @("feat: add OAuth2 login", "fix: typo in readme")
        Get-BumpType -Commits $commits | Should -Be "minor"
    }

    It "returns minor for feat with scope" {
        $commits = @("feat(auth): add JWT support")
        Get-BumpType -Commits $commits | Should -Be "minor"
    }

    It "returns patch for fix: commits only" {
        $commits = @("fix: correct null pointer", "fix: handle empty response")
        Get-BumpType -Commits $commits | Should -Be "patch"
    }

    It "returns patch for fix with scope" {
        $commits = @("fix(api): handle timeout correctly")
        Get-BumpType -Commits $commits | Should -Be "patch"
    }

    It "returns none for chore/docs/style commits" {
        $commits = @("chore: update deps", "docs: improve readme", "style: reformat")
        Get-BumpType -Commits $commits | Should -Be "none"
