#Requires -Modules Pester
# TDD test suite for SemanticVersionBumper.ps1
# Red/Green cycle: tests written first, then implementation added to make them pass.

BeforeAll {
    $script:scriptPath = Join-Path $PSScriptRoot "SemanticVersionBumper.ps1"
    . $script:scriptPath
}

# ---------------------------------------------------------------------------
# Helper function for act integration tests — defined at script scope so it
# is accessible from within Describe/It blocks (Pester 5 scoping rules).
# ---------------------------------------------------------------------------
function Invoke-ActTestCase {
    param(
        [string]$TestName,
        [string]$VersionJson,
        [string]$CommitsTxt
    )

    $tmpDir = Join-Path ([System.IO.Path]::GetTempPath()) ([System.Guid]::NewGuid().ToString())
    New-Item -ItemType Directory -Path $tmpDir | Out-Null
    New-Item -ItemType Directory -Path "$tmpDir/.github/workflows" -Force | Out-Null

    $workspaceRoot = $PSScriptRoot
    $scriptSrc    = Join-Path $workspaceRoot "SemanticVersionBumper.ps1"
    $workflowSrc  = Join-Path $workspaceRoot ".github/workflows/semantic-version-bumper.yml"
    $actrcSrc     = Join-Path $workspaceRoot ".actrc"

    # Copy script and workflow
    Copy-Item $scriptSrc  "$tmpDir/SemanticVersionBumper.ps1"
    Copy-Item $workflowSrc "$tmpDir/.github/workflows/semantic-version-bumper.yml"

    # Copy .actrc so act uses the correct container image
    if (Test-Path $actrcSrc) {
        Copy-Item $actrcSrc "$tmpDir/.actrc"
    }

    # Write test-case-specific files
    $VersionJson | Set-Content "$tmpDir/version.json" -Encoding UTF8
    $CommitsTxt  | Set-Content "$tmpDir/commits.txt"  -Encoding UTF8

    # Initialise git repo and commit all files
    Push-Location $tmpDir
    & git init --quiet
    & git config user.email "test@example.com"
    & git config user.name "Test Runner"
    & git add -A
    & git commit -m "test: $TestName" --quiet

    # Run act
    $actOutput = & act push --rm 2>&1
    $actExit   = $LASTEXITCODE
    Pop-Location

    # Cleanup
    Remove-Item -Recurse -Force $tmpDir -ErrorAction SilentlyContinue

    # Append to act-result.txt
    $actResultFile = Join-Path $PSScriptRoot "act-result.txt"
    $delimiter = "=" * 60
    Add-Content $actResultFile "`n$delimiter"
    Add-Content $actResultFile "TEST CASE: $TestName"
    Add-Content $actResultFile "EXIT CODE: $actExit"
    Add-Content $actResultFile $delimiter
    $actOutput | ForEach-Object { Add-Content $actResultFile $_ }
    Add-Content $actResultFile "$delimiter`n"

    return @{
        Output   = $actOutput
        ExitCode = $actExit
    }
}

